func NewAuthHandler(authSvc *auth.AuthService, db *gorm.DB, cfg *config.Config) *AuthHandler {
	return &AuthHandler{AuthSvc: authSvc, DB: db, Cfg: cfg}
}

func (h *AuthHandler) LoginPage(c *gin.Context) {
	c.HTML(http.StatusOK, "login.html", gin.H{
		"title": "Campus Portal - Login",
	})
}

func (h *AuthHandler) Login(c *gin.Context) {
	username := c.PostForm("username")
	password := c.PostForm("password")

	user, sessionID, err := h.AuthSvc.Login(username, password)
	if err != nil {
		c.HTML(http.StatusOK, "login.html", gin.H{
			"title": "Campus Portal - Login",
			"error": "Invalid username or password",
		})
		return
	}

	c.SetCookie("session_id", sessionID, 86400, "/", "", false, true)
	_ = user
	c.Redirect(http.StatusFound, "/dashboard")
}

func (h *AuthHandler) Logout(c *gin.Context) {
	sessionID, _ := c.Cookie("session_id")
	if sessionID != "" {
		h.AuthSvc.Logout(sessionID)
	}
	c.SetCookie("session_id", "", -1, "/", "", false, true)
	c.Redirect(http.StatusFound, "/login")
}

