	date, err := time.Parse("2006-01-02", dateStr)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid date format"})
		return
	}

	slots, err := h.BookingSvc.GetAvailableSlots(uint(venueID), date)
