1	package auth
2	
3	import (
4		"crypto/rand"
5		"encoding/hex"
6		"errors"
7		"time"
8	
9		"campus-portal/internal/models"
10	
11		"golang.org/x/crypto/bcrypt"
12		"gorm.io/gorm"
13	)
14	
15	type AuthService struct {
16		DB *gorm.DB
17	}
18	
19	func NewAuthService(db *gorm.DB) *AuthService {
20		return &AuthService{DB: db}
21	}
22	
23	func (s *AuthService) Register(username, password, fullName, email string, role models.Role, orgID uint, deptID *uint) (*models.User, error) {
24		hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
25		if err != nil {
26			return nil, err
27		}
28	
29		user := &models.User{
30			Username:       username,
31			PasswordHash:   string(hash),
32			FullName:       fullName,
33			Email:          email,
34			Role:           role,
35			OrganizationID: orgID,
36			DepartmentID:   deptID,
37			Active:         true,
38		}
39	
40		if err := s.DB.Create(user).Error; err != nil {
41			return nil, err
42		}
43		return user, nil
44	}
45	
46	func (s *AuthService) Login(username, password string) (*models.User, string, error) {
47		var user models.User
48		if err := s.DB.Where("username = ? AND active = true", username).First(&user).Error; err != nil {
49			if errors.Is(err, gorm.ErrRecordNotFound) {
50				return nil, "", errors.New("invalid credentials")
51			}
52			return nil, "", err
53		}
54	
55		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(password)); err != nil {
56			return nil, "", errors.New("invalid credentials")
57		}
58	
59		// Check for temporary elevated access
60		var tempAccess models.TempAccess
61		if err := s.DB.Where("user_id = ? AND reverted = false AND expires_at > ?", user.ID, time.Now()).
62			Order("created_at DESC").First(&tempAccess).Error; err == nil {
63			user.Role = tempAccess.GrantedRole
64		}
65	
66		sessionID, err := s.CreateSession(user.ID)
67		if err != nil {
68			return nil, "", err
69		}
70	
71		return &user, sessionID, nil
72	}
73	
74	func (s *AuthService) CreateSession(userID uint) (string, error) {
75		token := make([]byte, 32)
76		if _, err := rand.Read(token); err != nil {
77			return "", err
78		}
79		sessionID := hex.EncodeToString(token)
80	
81		session := &models.Session{
82			ID:        sessionID,
83			UserID:    userID,
84			ExpiresAt: time.Now().Add(24 * time.Hour),
85		}
86		if err := s.DB.Create(session).Error; err != nil {
87			return "", err
88		}
89		return sessionID, nil
90	}
91	
92	func (s *AuthService) ValidateSession(sessionID string) (*models.User, error) {
93		var session models.Session
94		if err := s.DB.Where("id = ? AND expires_at > ?", sessionID, time.Now()).First(&session).Error; err != nil {
95			return nil, errors.New("invalid or expired session")
96		}
97	
98		var user models.User
99		if err := s.DB.First(&user, session.UserID).Error; err != nil {
100			return nil, errors.New("user not found")
101		}
102	
103		if !user.Active {
104			return nil, errors.New("account deactivated")
105		}
106	
107		// Apply temp access if active
108		var tempAccess models.TempAccess
109		if err := s.DB.Where("user_id = ? AND reverted = false AND expires_at > ?", user.ID, time.Now()).
110			Order("created_at DESC").First(&tempAccess).Error; err == nil {
111			user.Role = tempAccess.GrantedRole
112		}
113	
114		return &user, nil
115	}
116	
117	func (s *AuthService) Logout(sessionID string) error {
118		return s.DB.Delete(&models.Session{}, "id = ?", sessionID).Error
119	}
120	
121	func (s *AuthService) GrantTempAccess(userID uint, grantedRole models.Role, grantedBy uint, duration time.Duration) error {
122		var user models.User
123		if err := s.DB.First(&user, userID).Error; err != nil {
124			return err
125		}
126	
127		ta := &models.TempAccess{
128			UserID:       userID,
129			GrantedRole:  grantedRole,
130			OriginalRole: user.Role,
131			GrantedBy:    grantedBy,
132			ExpiresAt:    time.Now().Add(duration),
133		}
134		return s.DB.Create(ta).Error
135	}
136	
137	func (s *AuthService) RevertExpiredAccess() {
138		var expired []models.TempAccess
139		s.DB.Where("reverted = false AND expires_at <= ?", time.Now()).Find(&expired)
140	
141		for _, ta := range expired {
142			s.DB.Model(&models.User{}).Where("id = ?", ta.UserID).Update("role", ta.OriginalRole)
143			s.DB.Model(&ta).Update("reverted", true)
144		}
145	}
146	
147	func (s *AuthService) ChangeUserRole(userID uint, newRole models.Role) error {
148		return s.DB.Model(&models.User{}).Where("id = ?", userID).Update("role", newRole).Error
149	}
150	
151	func (s *AuthService) ToggleUserActive(userID uint, active bool) error {
152		return s.DB.Model(&models.User{}).Where("id = ?", userID).Update("active", active).Error
153	}
154

