1	package middleware
2	
3	import (
4		"crypto/hmac"
5		"crypto/sha256"
6		"encoding/hex"
7		"fmt"
8		"log"
9		"net/http"
10		"strings"
11		"sync"
12		"time"
13	
14		"campus-portal/internal/auth"
