17		"github.com/gin-gonic/gin"
18		"gorm.io/gorm"
19	)
20	
21	// ===================== SESSION AUTH =====================
22	
23	func AuthRequired(authSvc *auth.AuthService) gin.HandlerFunc {
24		return func(c *gin.Context) {
25			sessionID, err := c.Cookie("session_id")
26			if err != nil || sessionID == "" {
27				if strings.HasPrefix(c.Request.URL.Path, "/api/") {
28					c.JSON(http.StatusUnauthorized, gin.H{"error": "authentication required"})
29				} else {
30					c.Redirect(http.StatusFound, "/login")
31				}
32				c.Abort()
33				return
34			}
35	
36			user, err := authSvc.ValidateSession(sessionID)
37			if err != nil {
38				c.SetCookie("session_id", "", -1, "/", "", false, true)
39				if strings.HasPrefix(c.Request.URL.Path, "/api/") {
40					c.JSON(http.StatusUnauthorized, gin.H{"error": err.Error()})
41				} else {
42					c.Redirect(http.StatusFound, "/login")
43				}
44				c.Abort()
45				return
46			}
