115	// ===================== HMAC SIGNING =====================
116	
117	func HMACAuth(secret string) gin.HandlerFunc {
118		return func(c *gin.Context) {
119			// Only enforce on /api/internal/* routes
120			if !strings.HasPrefix(c.Request.URL.Path, "/api/internal/") {
121				c.Next()
122				return
123			}
124	
125			signature := c.GetHeader("X-HMAC-Signature")
126			timestamp := c.GetHeader("X-HMAC-Timestamp")
127			if signature == "" || timestamp == "" {
128				c.JSON(http.StatusUnauthorized, gin.H{"error": "missing HMAC headers"})
129				c.Abort()
130				return
131			}
132	
133			// Verify timestamp is within 5 minutes
134			ts, err := time.Parse(time.RFC3339, timestamp)
135			if err != nil || time.Since(ts) > 5*time.Minute {
136				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid or expired timestamp"})
137				c.Abort()
138				return
139			}
140	
141			// Compute expected HMAC
142			message := fmt.Sprintf("%s:%s:%s", c.Request.Method, c.Request.URL.Path, timestamp)
143			mac := hmac.New(sha256.New, []byte(secret))
144			mac.Write([]byte(message))
145			expected := hex.EncodeToString(mac.Sum(nil))
146	
147			if !hmac.Equal([]byte(signature), []byte(expected)) {
148				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid HMAC signature"})
149				c.Abort()
150				return
151			}
152	
153			c.Next()
154		}
155	}
