157	// ===================== RATE LIMITER =====================
158	
159	type rateLimiter struct {
160		mu       sync.Mutex
161		clients  map[string]*clientWindow
162		limit    int
163		window   time.Duration
164	}
165	
166	type clientWindow struct {
167		count    int
168		resetAt  time.Time
169	}
170	
171	func NewRateLimiter(limit int, window time.Duration) *rateLimiter {
172		rl := &rateLimiter{
173			clients: make(map[string]*clientWindow),
174			limit:   limit,
175			window:  window,
176		}
177		// Cleanup goroutine
178		go func() {
179			ticker := time.NewTicker(1 * time.Minute)
180			defer ticker.Stop()
181			for range ticker.C {
182				rl.mu.Lock()
183				now := time.Now()
184				for ip, cw := range rl.clients {
185					if now.After(cw.resetAt) {
186						delete(rl.clients, ip)
187					}
188				}
189				rl.mu.Unlock()
190			}
191		}()
192		return rl
193	}
194	
195	func RateLimit(limit int) gin.HandlerFunc {
196		rl := NewRateLimiter(limit, time.Minute)
197	
198		return func(c *gin.Context) {
199			ip := c.ClientIP()
200			rl.mu.Lock()
201	
202			cw, exists := rl.clients[ip]
203			if !exists || time.Now().After(cw.resetAt) {
204				rl.clients[ip] = &clientWindow{count: 1, resetAt: time.Now().Add(rl.window)}
205				rl.mu.Unlock()
206				c.Next()
207				return
208			}
209	
210			if cw.count >= rl.limit {
211				rl.mu.Unlock()
212				c.JSON(http.StatusTooManyRequests, gin.H{
213					"error":       "rate limit exceeded",
214					"retry_after": time.Until(cw.resetAt).Seconds(),
215				})
216				c.Abort()
217				return
218			}
219	
220			cw.count++
221			rl.mu.Unlock()
222			c.Next()
223		}
224	}
