358	// ===================== PII MASKING =====================
359	
360	func MaskSSN(ssn string, role models.Role) string {
361		if ssn == "" {
362			return ""
363		}
364		if role == models.RoleAdmin {
365			return ssn
366		}
367		// Show only last 4 digits
368		clean := strings.ReplaceAll(strings.ReplaceAll(ssn, "-", ""), " ", "")
369		if len(clean) >= 4 {
370			return "***-**-" + clean[len(clean)-4:]
371		}
372		return "***-**-****"
373	}
374	
375	func MaskEmail(email string, role models.Role) string {
376		if role == models.RoleAdmin || role == models.RoleClinician {
377			return email
378		}
379		parts := strings.Split(email, "@")
380		if len(parts) != 2 {
381			return "***@***"
382		}
383		name := parts[0]
384		if len(name) > 2 {
385			name = name[:2] + "***"
386		}
387		return name + "@" + parts[1]
388	}
