21	// MatchPartners finds compatible training partners based on criteria
22	func (s *BookingService) MatchPartners(userID uint, skillRange int, weightRange float64, style string) ([]models.TrainerProfile, error) {
23		var requester models.TrainerProfile
24		if err := s.DB.Where("user_id = ?", userID).First(&requester).Error; err != nil {
25			return nil, errors.New("trainer profile not found")
26		}
27	
28		var matches []models.TrainerProfile
29		query := s.DB.Where("user_id != ?", userID)
30	
31		if skillRange > 0 {
32			query = query.Where("skill_level BETWEEN ? AND ?",
33				requester.SkillLevel-skillRange, requester.SkillLevel+skillRange)
34		}
35		if weightRange > 0 {
36			query = query.Where("weight_class BETWEEN ? AND ?",
37				requester.WeightClass-weightRange, requester.WeightClass+weightRange)
38		}
39		if style != "" {
40			query = query.Where("primary_style = ?", style)
41		}
42	
43		err := query.Find(&matches).Error
44		return matches, err
45	}
