47	// GetAvailableSlots returns available 30-min slots for a venue on a given date
48	func (s *BookingService) GetAvailableSlots(venueID uint, date time.Time) ([]time.Time, error) {
49		startOfDay := time.Date(date.Year(), date.Month(), date.Day(), 8, 0, 0, 0, date.Location())
50		endOfDay := time.Date(date.Year(), date.Month(), date.Day(), 20, 0, 0, 0, date.Location())
51	
52		// Get existing bookings for this venue and date
53		var bookings []models.Booking
54		s.DB.Where("venue_id = ? AND slot_start >= ? AND slot_start < ? AND status != ?",
55			venueID, startOfDay, endOfDay, models.BookingCanceled).Find(&bookings)
56	
57		bookedTimes := make(map[int64]bool)
58		for _, b := range bookings {
59			bookedTimes[b.SlotStart.Unix()] = true
60		}
61	
62		var available []time.Time
63		for t := startOfDay; t.Before(endOfDay); t = t.Add(30 * time.Minute) {
64			if !bookedTimes[t.Unix()] {
65				available = append(available, t)
66			}
67		}
68	
69		return available, nil
70	}
