72	// CheckConflicts detects double-bookings or venue overlaps
73	func (s *BookingService) CheckConflicts(requesterID uint, partnerID *uint, venueID uint, slotStart time.Time) ([]string, error) {
74		slotEnd := slotStart.Add(30 * time.Minute)
75		var conflicts []string
76	
77		// Check requester conflicts
78		var count int64
79		s.DB.Model(&models.Booking{}).Where(
80			"requester_id = ? AND slot_start < ? AND slot_end > ? AND status NOT IN ?",
81			requesterID, slotEnd, slotStart, []string{string(models.BookingCanceled), string(models.BookingRefunded)},
82		).Count(&count)
83		if count > 0 {
84			conflicts = append(conflicts, "You already have a booking during this time slot")
85		}
86	
87		// Check partner conflicts
88		if partnerID != nil {
89			s.DB.Model(&models.Booking{}).Where(
90				"(requester_id = ? OR partner_id = ?) AND slot_start < ? AND slot_end > ? AND status NOT IN ?",
91				*partnerID, *partnerID, slotEnd, slotStart, []string{string(models.BookingCanceled), string(models.BookingRefunded)},
92			).Count(&count)
93			if count > 0 {
94				conflicts = append(conflicts, "Selected partner has a conflicting booking")
95			}
96		}
97	
98		// Check venue overlap
99		s.DB.Model(&models.Booking{}).Where(
100			"venue_id = ? AND slot_start < ? AND slot_end > ? AND status NOT IN ?",
101			venueID, slotEnd, slotStart, []string{string(models.BookingCanceled), string(models.BookingRefunded)},
102		).Count(&count)
103	
104		var venue models.Venue
105		s.DB.First(&venue, venueID)
106		if venue.RoomType != "virtual" && count > 0 {
107			conflicts = append(conflicts, "Venue is already booked for this time slot")
108		}
109	
110		return conflicts, nil
111	}
