113	// CreateBooking creates a new booking after validation
114	func (s *BookingService) CreateBooking(requesterID uint, partnerID *uint, venueID uint, slotStart time.Time, changedBy uint) (*models.Booking, error) {
115		conflicts, err := s.CheckConflicts(requesterID, partnerID, venueID, slotStart)
116		if err != nil {
117			return nil, err
118		}
119		if len(conflicts) > 0 {
120			return nil, errors.New("booking conflicts: " + conflicts[0])
121		}
122	
123		booking := &models.Booking{
124			RequesterID: requesterID,
125			PartnerID:   partnerID,
126			VenueID:     venueID,
127			SlotStart:   slotStart,
128			SlotEnd:     slotStart.Add(30 * time.Minute),
129			Status:      models.BookingInitiated,
130		}
131	
132		err = s.DB.Transaction(func(tx *gorm.DB) error {
133			if err := tx.Create(booking).Error; err != nil {
134				return err
135			}
136			return tx.Create(&models.BookingAudit{
137				BookingID: booking.ID,
138				ChangedBy: changedBy,
139				OldStatus: "",
140				NewStatus: string(models.BookingInitiated),
141				Note:      "Booking initiated",
142				Timestamp: time.Now(),
143			}).Error
144		})
145	
146		return booking, err
147	}
