149	// TransitionBooking moves a booking to a new state
150	func (s *BookingService) TransitionBooking(bookingID uint, newStatus models.BookingStatus, changedBy uint, note string) error {
151		var booking models.Booking
152		if err := s.DB.First(&booking, bookingID).Error; err != nil {
153			return err
154		}
155	
156		// Validate state transition
157		valid := map[models.BookingStatus][]models.BookingStatus{
158			models.BookingInitiated: {models.BookingConfirmed, models.BookingCanceled},
159			models.BookingConfirmed: {models.BookingCanceled},
160			models.BookingCanceled:  {models.BookingRefunded},
161		}
162	
163		allowed, ok := valid[booking.Status]
164		if !ok {
165			return errors.New("booking is in a terminal state")
166		}
167	
168		isAllowed := false
169		for _, s := range allowed {
170			if s == newStatus {
171				isAllowed = true
172				break
173			}
174		}
175		if !isAllowed {
176			return errors.New("invalid state transition")
177		}
178	
179		// Enforce 2-hour cancellation rule
180		if newStatus == models.BookingCanceled {
181			if time.Until(booking.SlotStart) < 2*time.Hour {
182				return errors.New("cannot cancel less than 2 hours before the session")
183			}
184		}
185	
186		return s.DB.Transaction(func(tx *gorm.DB) error {
187			oldStatus := booking.Status
188			booking.Status = newStatus
189			if err := tx.Save(&booking).Error; err != nil {
190				return err
191			}
192			return tx.Create(&models.BookingAudit{
193				BookingID: bookingID,
194				ChangedBy: changedBy,
195				OldStatus: string(oldStatus),
196				NewStatus: string(newStatus),
197				Note:      note,
198				Timestamp: time.Now(),
199			}).Error
200		})
201	}
