128	func (s *MenuService) IsWithinSellWindow(itemID uint, now time.Time) (bool, error) {
129		// Check holiday blackout
130		var blackout models.HolidayBlackout
131		today := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())
132		if err := s.DB.Where("date = ?", today).First(&blackout).Error; err == nil {
133			return false, nil // Blacked out
134		}
135	
136		var windows []models.SellWindow
137		s.DB.Where("menu_item_id = ? AND day_of_week = ?", itemID, int(now.Weekday())).Find(&windows)
138	
139		if len(windows) == 0 {
140			return true, nil // No windows defined = always available
141		}
142	
143		currentTime := fmt.Sprintf("%02d:%02d", now.Hour(), now.Minute())
144		for _, w := range windows {
145			if currentTime >= w.OpenTime && currentTime <= w.CloseTime {
146				return true, nil
147			}
148		}
149	
150		return false, nil
151	}
