180	// Pricing
181	func (s *MenuService) CalculatePrice(itemID uint, orderType string, isMember bool) (float64, error) {
182		item, err := s.GetMenuItem(itemID)
183		if err != nil {
184			return 0, err
185		}
186	
187		var price float64
188		if orderType == "takeout" {
189			price = item.BasePriceTakeout
190		} else {
191			price = item.BasePriceDineIn
192		}
193	
194		// Apply member discount
195		if isMember && item.MemberDiscount > 0 {
196			price -= price * (item.MemberDiscount / 100)
197		}
198	
199		// Apply active promotions
200		promos, _ := s.GetActivePromotions(itemID)
201		for _, p := range promos {
202			price -= price * (p.DiscountPct / 100)
203		}
204	
205		if price < 0 {
206			price = 0
207		}
208	
209		return price, nil
210	}
