212	// Orders
213	func (s *MenuService) CreateOrder(order *models.MenuOrder, items []models.MenuOrderItem) error {
214		return s.DB.Transaction(func(tx *gorm.DB) error {
215			// Validate all items are within sell window
216			for _, oi := range items {
217				available, _ := s.IsWithinSellWindow(oi.MenuItemID, time.Now())
218				if !available {
219					var mi models.MenuItem
220					tx.First(&mi, oi.MenuItemID)
221					return errors.New("item not available: " + mi.Name)
222				}
223				var mi models.MenuItem
224				tx.First(&mi, oi.MenuItemID)
225				if mi.SoldOut {
226					return errors.New("item sold out: " + mi.Name)
227				}
228			}
229	
230			if err := tx.Create(order).Error; err != nil {
231				return err
232			}
233	
234			for i := range items {
235				items[i].OrderID = order.ID
236				if err := tx.Create(&items[i]).Error; err != nil {
237					return err
238				}
239			}
240	
241			return nil
242		})
243	}
