23	func (s *AuthService) Register(username, password, fullName, email string, role models.Role, orgID uint, deptID *uint) (*models.User, error) {
24		hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
25		if err != nil {
26			return nil, err
27		}
28	
29		user := &models.User{
30			Username:       username,
31			PasswordHash:   string(hash),
32			FullName:       fullName,
33			Email:          email,
34			Role:           role,
35			OrganizationID: orgID,
36			DepartmentID:   deptID,
37			Active:         true,
38		}
39	
40		if err := s.DB.Create(user).Error; err != nil {
41			return nil, err
42		}
43		return user, nil
44	}
