46	func (s *AuthService) Login(username, password string) (*models.User, string, error) {
47		var user models.User
48		if err := s.DB.Where("username = ? AND active = true", username).First(&user).Error; err != nil {
49			if errors.Is(err, gorm.ErrRecordNotFound) {
50				return nil, "", errors.New("invalid credentials")
51			}
52			return nil, "", err
53		}
54	
55		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(password)); err != nil {
56			return nil, "", errors.New("invalid credentials")
57		}
58	
59		// Check for temporary elevated access
60		var tempAccess models.TempAccess
61		if err := s.DB.Where("user_id = ? AND reverted = false AND expires_at > ?", user.ID, time.Now()).
62			Order("created_at DESC").First(&tempAccess).Error; err == nil {
63			user.Role = tempAccess.GrantedRole
64		}
65	
66		sessionID, err := s.CreateSession(user.ID)
67		if err != nil {
68			return nil, "", err
69		}
70	
71		return &user, sessionID, nil
72	}
