74	func (s *AuthService) CreateSession(userID uint) (string, error) {
75		token := make([]byte, 32)
76		if _, err := rand.Read(token); err != nil {
77			return "", err
78		}
79		sessionID := hex.EncodeToString(token)
80	
81		session := &models.Session{
82			ID:        sessionID,
83			UserID:    userID,
84			ExpiresAt: time.Now().Add(24 * time.Hour),
85		}
86		if err := s.DB.Create(session).Error; err != nil {
87			return "", err
88		}
89		return sessionID, nil
90	}
