92	func (s *AuthService) ValidateSession(sessionID string) (*models.User, error) {
93		var session models.Session
94		if err := s.DB.Where("id = ? AND expires_at > ?", sessionID, time.Now()).First(&session).Error; err != nil {
95			return nil, errors.New("invalid or expired session")
96		}
97	
98		var user models.User
99		if err := s.DB.First(&user, session.UserID).Error; err != nil {
100			return nil, errors.New("user not found")
101		}
102	
103		if !user.Active {
104			return nil, errors.New("account deactivated")
105		}
106	
107		// Apply temp access if active
108		var tempAccess models.TempAccess
109		if err := s.DB.Where("user_id = ? AND reverted = false AND expires_at > ?", user.ID, time.Now()).
110			Order("created_at DESC").First(&tempAccess).Error; err == nil {
111			user.Role = tempAccess.GrantedRole
112		}
113	
114		return &user, nil
115	}
