1	// ===================== FILE UPLOAD VALIDATION =====================
2	function validateFile(input) {
3	    const fileError = document.getElementById('fileError');
4	    const fileSuccess = document.getElementById('fileSuccess');
5	    const uploadBtn = document.getElementById('uploadBtn');
6	
7	    fileError.style.display = 'none';
8	    fileSuccess.style.display = 'none';
9	    uploadBtn.disabled = true;
10	
11	    if (!input.files || !input.files[0]) return;
12	
13	    const file = input.files[0];
14	    const maxSize = 10 * 1024 * 1024; // 10MB
15	    const allowedTypes = ['application/pdf', 'image/jpeg', 'image/png', 'image/gif'];
16	
17	    if (file.size > maxSize) {
18	        fileError.textContent = 'File exceeds 10MB limit. Please choose a smaller file.';
19	        fileError.style.display = 'block';
20	        input.value = '';
21	        return;
22	    }
23	
24	    if (!allowedTypes.includes(file.type)) {
25	        fileError.textContent = 'Invalid file type. Only PDF, JPEG, PNG, and GIF files are accepted.';
26	        fileError.style.display = 'block';
27	        input.value = '';
28	        return;
29	    }
30	
31	    fileSuccess.textContent = `File "${file.name}" (${(file.size / 1024).toFixed(1)} KB) ready to upload.`;
32	    fileSuccess.style.display = 'block';
33	    uploadBtn.disabled = false;
34	}
