36	// Handle upload form submission
37	document.addEventListener('DOMContentLoaded', function() {
38	    const uploadForm = document.getElementById('uploadForm');
39	    if (uploadForm) {
40	        uploadForm.addEventListener('submit', function(e) {
41	            e.preventDefault();
42	            const formData = new FormData(this);
43	            const uploadBtn = document.getElementById('uploadBtn');
44	            const fileSuccess = document.getElementById('fileSuccess');
45	            const fileError = document.getElementById('fileError');
46	
47	            uploadBtn.disabled = true;
48	            uploadBtn.textContent = 'Uploading...';
49	
50	            fetch('/health/upload', {
51	                method: 'POST',
52	                body: formData
53	            })
54	            .then(res => res.json())
55	            .then(data => {
56	                if (data.error) {
57	                    fileError.textContent = data.error;
58	                    fileError.style.display = 'block';
59	                    fileSuccess.style.display = 'none';
60	                } else {
61	                    fileSuccess.textContent = 'File uploaded successfully!';
62	                    fileSuccess.style.display = 'block';
63	                    fileError.style.display = 'none';
64	                    setTimeout(() => location.reload(), 1500);
65	                }
66	            })
67	            .catch(err => {
68	                fileError.textContent = 'Upload failed: ' + err.message;
69	                fileError.style.display = 'block';
70	            })
71	            .finally(() => {
72	                uploadBtn.disabled = false;
73	                uploadBtn.textContent = 'Upload';
74	            });
75	        });
76	    }
77	});
