79	// ===================== DRAFT SAVE/RESTORE =====================
80	function saveDraft(formId) {
81	    const form = document.getElementById(formId);
82	    if (!form) return;
83	
84	    const data = {};
85	    const inputs = form.querySelectorAll('input, textarea, select');
86	    inputs.forEach(input => {
87	        if (input.name && input.type !== 'hidden' && input.type !== 'submit') {
88	            data[input.name] = input.value;
89	        }
90	    });
91	
92	    localStorage.setItem('draft_' + formId, JSON.stringify(data));
93	}
94	
95	function restoreDraft(formId) {
96	    const saved = localStorage.getItem('draft_' + formId);
97	    if (!saved) return;
98	
99	    try {
100	        const data = JSON.parse(saved);
101	        const form = document.getElementById(formId);
102	        if (!form) return;
103	
104	        Object.keys(data).forEach(key => {
105	            const input = form.querySelector(`[name="${key}"]`);
106	            if (input && input.type !== 'hidden') {
107	                input.value = data[key];
108	            }
109	        });
110	    } catch (e) {
111	        console.error('Failed to restore draft:', e);
112	    }
113	}
114	
115	function clearDraft(formId) {
116	    localStorage.removeItem('draft_' + formId);
117	    const form = document.getElementById(formId);
118	    if (form) form.reset();
119	}
