197	    let url = `/api/check-conflicts?venue_id=${venueId}&slot_start=${slotStart}`;
198	    if (partnerId) url += `&partner_id=${partnerId}`;
199	
200	    // Synchronous check (blocking for UX)
201	    const xhr = new XMLHttpRequest();
202	    xhr.open('GET', url, false);
203	    xhr.send();
204	
205	    if (xhr.status === 200) {
206	        const data = JSON.parse(xhr.responseText);
207	        if (data.conflicts && data.conflicts.length > 0) {
208	            warning.innerHTML = '<strong>Conflicts detected:</strong><ul>' +
209	                data.conflicts.map(c => `<li>${c}</li>`).join('') + '</ul>';
210	            warning.style.display = 'block';
211	            return false;
212	        }
213	    }
214	
215	    return true;
216	}
