// CSRFProtect generates and validates CSRF tokens for state-changing requests.
// Tokens are stored in the user's session and must be included in POST forms.
func CSRFProtect() gin.HandlerFunc {
	return func(c *gin.Context) {
		if c.Request.Method == "GET" || c.Request.Method == "HEAD" || c.Request.Method == "OPTIONS" {
			// Generate token for GET requests so forms can include it
			token := generateCSRFToken(c)
			c.Set("csrf_token", token)
			c.Next()
			return
		}

		// For POST/PUT/DELETE, validate the token
		// Skip for JSON API endpoints (they use HMAC or session auth)
		contentType := c.GetHeader("Content-Type")
		if strings.Contains(contentType, "application/json") || strings.Contains(contentType, "multipart/form-data") {
			c.Next()
			return
		}

		sessionToken := getCSRFFromCookie(c)
		formToken := c.PostForm("csrf_token")

		if sessionToken == "" || formToken == "" || sessionToken != formToken {
			c.JSON(http.StatusForbidden, gin.H{"error": "invalid CSRF token"})
			c.Abort()
			return
		}

		c.Set("csrf_token", sessionToken)
		c.Next()
	}
}

func generateCSRFToken(c *gin.Context) string {
	existing := getCSRFFromCookie(c)
	if existing != "" {
		return existing
	}
	b := make([]byte, 32)
	rand.Read(b)
	token := hex.EncodeToString(b)
	c.SetCookie("csrf_token", token, 86400, "/", "", false, true)
	return token
}

func getCSRFFromCookie(c *gin.Context) string {
	token, _ := c.Cookie("csrf_token")
	return token
}

