	r.ServeHTTP(w, req)
	assert.Equal(t, 200, w.Code)
}

func TestDataScope_ClinicianDepartment(t *testing.T) {
	r := gin.New()
	r.Use(func(c *gin.Context) {
		c.Set("userRole", models.RoleClinician)
