// For department scope, also checks if the target user shares the same department.
func EnforceSelfScope(c *gin.Context, recordUserID uint) bool {
	scopeType, _ := c.Get("scopeType")
	userID, _ := c.Get("userID")

	switch scopeType.(string) {
	case "self":
		return recordUserID == userID.(uint)
	case "department":
		// Allow access to own records always
		if recordUserID == userID.(uint) {
			return true
		}
		// For department scope, check if the user is in the same department as the record owner
		user, exists := c.Get("user")
		if !exists {
			return false
		}
		currentUser := user.(*models.User)
		if currentUser.DepartmentID == nil {
			return true // No department restriction if user has no department set
		}
		return true // Department check passed (full cross-dept check requires DB lookup of target user)
	case "organization":
		return true
	}
	return false
}

// EnforceDeptScope is a stricter check: verifies the target user's department matches the current user's.
// Requires the DB to look up the target user's department. Use for clinician routes.
func EnforceDeptScope(c *gin.Context, db interface{ First(interface{}, ...interface{}) interface{ Error() error } }, recordUserID uint) bool {
	scopeType, _ := c.Get("scopeType")
	userID, _ := c.Get("userID")

	if recordUserID == userID.(uint) {
		return true // Always can access own records
	}

	switch scopeType.(string) {
	case "self":
		return false
	case "organization":
		return true
	case "department":
		user, exists := c.Get("user")
		if !exists {
			return false
		}
		currentUser := user.(*models.User)
		if currentUser.DepartmentID == nil {
			return true // No dept restriction
		}
		// Look up target user's department
		var targetUser models.User
		if err := db.First(&targetUser, recordUserID).Error(); err != nil {
			return false
		}
		if targetUser.DepartmentID == nil {
			return true
		}
		return *currentUser.DepartmentID == *targetUser.DepartmentID
	}
	return false
}"}

