function loadSlots() {
    const venueId = document.getElementById('venueSelect')?.value;
    const date = document.getElementById('bookingDate')?.value;
    const slotSelect = document.getElementById('slotSelect');

    if (!venueId || !date || !slotSelect) return;

    slotSelect.innerHTML = '<option value="">Loading...</option>';

    fetch(`/api/slots?venue_id=${venueId}&date=${date}`)
        .then(res => res.json())
        .then(data => {
            slotSelect.innerHTML = '';
            if (!data.slots || data.slots.length === 0) {
                slotSelect.innerHTML = '<option value="">No slots available</option>';
                return;
            }
            data.slots.forEach(slot => {
                const d = new Date(slot);
                const opt = document.createElement('option');
                opt.value = slot;
                opt.textContent = d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
                slotSelect.appendChild(opt);
            });
        })
        .catch(() => {
            slotSelect.innerHTML = '<option value="">Error loading slots</option>';
        });
}", "new_string": "// ===================== BOOKING CALENDAR GRID =====================
let selectedSlotValue = null;

function loadCalendar() {
    const venueId = document.getElementById('venueSelect')?.value;
    const date = document.getElementById('bookingDate')?.value;
    const grid = document.getElementById('calendarGrid');
    const hiddenInput = document.getElementById('slotStartHidden');

    if (!venueId || !date || !grid) return;

    grid.innerHTML = '<p class="text-muted">Loading slots...</p>';
    selectedSlotValue = null;
    if (hiddenInput) hiddenInput.value = '';

    fetch(`/api/slots?venue_id=${venueId}&date=${date}`)
        .then(res => res.json())
        .then(data => {
            grid.innerHTML = '';

            // Build all 24 possible half-hour slots from 8AM–8PM
            const allSlots = [];
            for (let h = 8; h < 20; h++) {
                for (let m = 0; m < 60; m += 30) {
                    allSlots.push({ hour: h, minute: m });
                }
            }

            // Build set of available slot timestamps
            const availableSet = new Set();
            if (data.slots) {
                data.slots.forEach(s => {
                    const d = new Date(s);
                    availableSet.add(d.getHours() * 60 + d.getMinutes());
                });
            }

            // Render the grid
            allSlots.forEach(slot => {
                const key = slot.hour * 60 + slot.minute;
                const available = availableSet.has(key);
                const timeStr = String(slot.hour).padStart(2, '0') + ':' + String(slot.minute).padStart(2, '0');
                const label = new Date(2000, 0, 1, slot.hour, slot.minute)
                    .toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });

                const cell = document.createElement('div');
                cell.className = 'calendar-slot ' + (available ? 'slot-available' : 'slot-booked');
                cell.textContent = label;
                cell.title = available ? 'Available — click to select' : 'Already booked';

                if (available) {
                    // Reconstruct the full ISO datetime for the slot
                    const slotISO = date + 'T' + timeStr + ':00';
                    cell.addEventListener('click', function() {
                        // Deselect previous
                        grid.querySelectorAll('.slot-selected').forEach(el => el.classList.remove('slot-selected'));
                        cell.classList.add('slot-selected');
                        selectedSlotValue = slotISO;
                        if (hiddenInput) hiddenInput.value = slotISO;

                        // Auto-check conflicts
                        const warning = document.getElementById('conflictWarning');
                        if (warning) warning.style.display = 'none';
                    });
                }

                grid.appendChild(cell);
            });

            if (allSlots.length === 0) {
                grid.innerHTML = '<p class="text-muted">No slots for this date.</p>';
            }
        })
        .catch(() => {
            grid.innerHTML = '<p class="text-muted">Error loading slots.</p>';
        });
}

// Keep backward compat for old loadSlots calls
function loadSlots() { loadCalendar(); }"}

