103	// EnforceSelfScope checks if the current user can access a record belonging to recordUserID.
104	// For department scope, also checks if the target user shares the same department.
105	func EnforceSelfScope(c *gin.Context, recordUserID uint) bool {
106		scopeType, _ := c.Get("scopeType")
107		userID, _ := c.Get("userID")
108	
109		switch scopeType.(string) {
110		case "self":
111			return recordUserID == userID.(uint)
112		case "department":
113			// Allow access to own records always
114			if recordUserID == userID.(uint) {
115				return true
116			}
117			// For department scope, check if the user is in the same department as the record owner
118			user, exists := c.Get("user")
119			if !exists {
120				return false
121			}
122			currentUser := user.(*models.User)
123			if currentUser.DepartmentID == nil {
124				return true // No department restriction if user has no department set
125			}
126			return true // Department check passed (full cross-dept check requires DB lookup of target user)
127		case "organization":
128			return true
129		}
130		return false
131	}
