133	// EnforceDeptScope is a stricter check: verifies the target user's department matches.
134	// Requires the DB to look up the target user's department. Use for clinician routes.
135	func EnforceDeptScope(c *gin.Context, db *gorm.DB, recordUserID uint) bool {
136		scopeType, _ := c.Get("scopeType")
137		userID, _ := c.Get("userID")
138	
139		if recordUserID == userID.(uint) {
140			return true
141		}
142	
143		switch scopeType.(string) {
144		case "self":
145			return false
146		case "organization":
147			return true
148		case "department":
149			user, exists := c.Get("user")
150			if !exists {
151				return false
152			}
153			currentUser := user.(*models.User)
154			if currentUser.DepartmentID == nil {
155				return true
156			}
157			var targetUser models.User
158			if err := db.First(&targetUser, recordUserID).Error; err != nil {
159				return false
160			}
161			if targetUser.DepartmentID == nil {
162				return true
163			}
164			return *currentUser.DepartmentID == *targetUser.DepartmentID
165		}
166		return false
167	}
