13	// FieldEncryptor provides AES-256-GCM encryption for sensitive fields at rest.
14	var fieldEncryptionKey []byte
15	
16	func InitEncryption() error {
17		key := os.Getenv("FIELD_ENCRYPTION_KEY")
18		if key == "" {
19			// Generate a random key and warn — production must set this env var
20			fieldEncryptionKey = make([]byte, 32)
21			if _, err := rand.Read(fieldEncryptionKey); err != nil {
22				return err
23			}
24			return nil
25		}
26		decoded, err := base64.StdEncoding.DecodeString(key)
27		if err != nil {
28			return errors.New("FIELD_ENCRYPTION_KEY must be base64-encoded 32 bytes")
29		}
30		if len(decoded) != 32 {
31			return errors.New("FIELD_ENCRYPTION_KEY must decode to exactly 32 bytes")
32		}
33		fieldEncryptionKey = decoded
34		return nil
35	}
36	
37	// EncryptField encrypts a plaintext string using AES-256-GCM.
38	// Returns a base64-encoded ciphertext. Empty input returns empty output.
39	func EncryptField(plaintext string) (string, error) {
40		if plaintext == "" {
41			return "", nil
42		}
43		block, err := aes.NewCipher(fieldEncryptionKey)
44		if err != nil {
45			return "", err
46		}
47		gcm, err := cipher.NewGCM(block)
48		if err != nil {
49			return "", err
50		}
51		nonce := make([]byte, gcm.NonceSize())
52		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
53			return "", err
54		}
55		ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
56		return base64.StdEncoding.EncodeToString(ciphertext), nil
57	}
58	
59	// DecryptField decrypts a base64-encoded AES-256-GCM ciphertext.
60	// Empty input returns empty output.
61	func DecryptField(encoded string) (string, error) {
62		if encoded == "" {
63			return "", nil
64		}
65		data, err := base64.StdEncoding.DecodeString(encoded)
66		if err != nil {
67			return "", err
68		}
69		block, err := aes.NewCipher(fieldEncryptionKey)
70		if err != nil {
71			return "", err
72		}
73		gcm, err := cipher.NewGCM(block)
74		if err != nil {
75			return "", err
76		}
77		nonceSize := gcm.NonceSize()
78		if len(data) < nonceSize {
79			return "", errors.New("ciphertext too short")
80		}
81		nonce, ciphertext := data[:nonceSize], data[nonceSize:]
82		plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
83		if err != nil {
84			return "", err
85		}
86		return string(plaintext), nil
87	}
