343	function showBookingAudit(bookingId) {
344	    const modal = document.getElementById('auditModal');
345	    const content = document.getElementById('auditContent');
346	
347	    if (!modal || !content) return;
348	
349	    content.innerHTML = 'Loading...';
350	    modal.style.display = 'flex';
351	
352	    fetch(`/bookings/${bookingId}/audit`)
353	        .then(res => res.json())
354	        .then(data => {
355	            if (!data.audits || data.audits.length === 0) {
356	                content.innerHTML = '<p>No audit records found.</p>';
357	                return;
358	            }
359	            let html = '<table class="table table-sm"><thead><tr><th>Time</th><th>From</th><th>To</th><th>By</th><th>Note</th></tr></thead><tbody>';
360	            data.audits.forEach(a => {
361	                const time = new Date(a.timestamp).toLocaleString('en-US');
362	                html += `<tr><td>${time}</td><td>${a.old_status || '-'}</td><td><span class="status-badge status-${a.new_status}">${a.new_status}</span></td><td>${a.changed_by}</td><td>${a.note}</td></tr>`;
363	            });
364	            html += '</tbody></table>';
365	            content.innerHTML = html;
366	        })
367	        .catch(() => {
368	            content.innerHTML = '<p>Error loading audit trail.</p>';
369	        });
370	}
