)

// Render renders a templ.Component into a Gin response.
func Render(c *gin.Context, status int, component templ.Component) {
	c.Status(status)
	c.Header("Content-Type", "text/html; charset=utf-8")
	if err := component.Render(c.Request.Context(), c.Writer); err != nil {
		c.String(http.StatusInternalServerError, "render error: %v", err)
	}
}

// UserInfoFromContext extracts user info from the Gin context for use in templates.
func UserInfoFromContext(c *gin.Context) *UserInfo {
	u, exists := c.Get("user")
	if !exists {
		return nil
	}
	type hasRoleAndName interface {
		GetRole() string
		GetFullName() string
	}
	// Use type assertion for the models.User struct
	type userLike struct {
		FullName string
		Role     interface{}
	}
	// Generic approach using reflection-free interface
	return extractUserInfo(u)
}

func extractUserInfo(u interface{}) *UserInfo {
	// Use fmt.Sprintf to get string representation of role
	type basicUser interface {
		GetID() uint
	}
	// Simple struct field access via interface
	if user, ok := u.(interface {
		GetFullName() string
		GetRoleStr() string
	}); ok {
		return &UserInfo{FullName: user.GetFullName(), Role: user.GetRoleStr()}
	}
	return nil
}
"}

