306	func (s *ReportingService) RefreshMaterializedViews() {
307		views := []string{"mv_clinic_utilization", "mv_booking_fill_rates", "mv_menu_sell_through"}
308		for _, v := range views {
309			start := time.Now()
310			// Try CONCURRENTLY first (requires unique index); fall back to blocking refresh
311			result := s.DB.Exec(fmt.Sprintf("REFRESH MATERIALIZED VIEW CONCURRENTLY %s", v))
312			if result.Error != nil {
313				s.DB.Exec(fmt.Sprintf("REFRESH MATERIALIZED VIEW %s", v))
314			}
315			log.Printf("Refreshed %s in %v", v, time.Since(start))
316		}
317	}
