331	func (s *ReportingService) cachedQuery(key, query string) ([]map[string]interface{}, error) {
332		s.mu.RLock()
333		if entry, ok := s.cache[key]; ok && time.Now().Before(entry.expiresAt) {
334			s.mu.RUnlock()
335			return entry.data.([]map[string]interface{}), nil
336		}
337		s.mu.RUnlock()
338	
339		var results []map[string]interface{}
340		rows, err := s.DB.Raw(query).Rows()
341		if err != nil {
342			return nil, err
343		}
344		defer rows.Close()
345	
346		cols, _ := rows.Columns()
347		for rows.Next() {
348			row := make(map[string]interface{})
349			vals := make([]interface{}, len(cols))
350			valPtrs := make([]interface{}, len(cols))
351			for i := range vals {
352				valPtrs[i] = &vals[i]
353			}
354			rows.Scan(valPtrs...)
355			for i, col := range cols {
356				row[col] = vals[i]
357			}
358			results = append(results, row)
359		}
360	
361		s.mu.Lock()
362		s.cache[key] = &cacheEntry{data: results, expiresAt: time.Now().Add(s.cacheTTL)}
363		s.mu.Unlock()

