		OrderType:  "dine_in",
		TotalPrice: 20.00,
		IsMember:   false,
		Status:     "pending",
	}
	items := []models.MenuOrderItem{
		{MenuItemID: item.ID, Quantity: 2, UnitPrice: 10.00},
