230	func (s *WebhookService) deliver(endpoint models.WebhookEndpoint, payload []byte) {
231		// Sign the payload
232		mac := hmac.New(sha256.New, []byte(endpoint.Secret))
233		mac.Write(payload)
234		signature := hex.EncodeToString(mac.Sum(nil))
235	
236		req, err := http.NewRequest("POST", endpoint.URL, bytes.NewReader(payload))
237		if err != nil {
238			s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), 1)
239			return
240		}
241	
242		req.Header.Set("Content-Type", "application/json")
243		req.Header.Set("X-Webhook-Signature", signature)
244		req.Header.Set("X-Webhook-Event", endpoint.EventType)
245	
246		maxRetries := 3
247		for attempt := 1; attempt <= maxRetries; attempt++ {
248			resp, err := s.client.Do(req)
249			if err != nil {
250				if attempt == maxRetries {
251					s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), attempt)
252				}
253				time.Sleep(time.Duration(attempt) * time.Second)
254				continue
255			}
256			defer resp.Body.Close()
257			s.logDelivery(endpoint.ID, string(payload), resp.StatusCode, "", attempt)
258			return
259		}
260	}
