193	function loadCalendar() {
194	    const venueId = document.getElementById('venueSelect')?.value;
195	    const date = document.getElementById('bookingDate')?.value;
196	    const grid = document.getElementById('calendarGrid');
197	    const hiddenInput = document.getElementById('slotStartHidden');
198	
199	    if (!venueId || !date || !grid) return;
200	
201	    grid.innerHTML = '<p class="text-muted">Loading slots...</p>';
202	    selectedSlotValue = null;
203	    if (hiddenInput) hiddenInput.value = '';
204	
205	    fetch(`/api/slots?venue_id=${venueId}&date=${date}`)
206	        .then(res => res.json())
207	        .then(data => {
208	            grid.innerHTML = '';
209	
210	            // Build all 24 possible half-hour slots from 8AM–8PM
211	            const allSlots = [];
212	            for (let h = 8; h < 20; h++) {
213	                for (let m = 0; m < 60; m += 30) {
214	                    allSlots.push({ hour: h, minute: m });
215	                }
216	            }
217	
218	            // Build set of available slot timestamps
219	            const availableSet = new Set();
220	            if (data.slots) {
221	                data.slots.forEach(s => {
222	                    const d = new Date(s);
223	                    availableSet.add(d.getHours() * 60 + d.getMinutes());
224	                });
225	            }
226	
227	            // Render the grid
228	            allSlots.forEach(slot => {
229	                const key = slot.hour * 60 + slot.minute;
230	                const available = availableSet.has(key);
231	                const timeStr = String(slot.hour).padStart(2, '0') + ':' + String(slot.minute).padStart(2, '0');
232	                const label = new Date(2000, 0, 1, slot.hour, slot.minute)
233	                    .toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
234	
