	bookedTimes := make(map[int64]bool)
	for _, b := range bookings {
		bookedTimes[b.SlotStart.Unix()] = true
	}

	var slots []SlotInfo
	for t := startOfDay; t.Before(endOfDay); t = t.Add(30 * time.Minute) {
		slots = append(slots, SlotInfo{
			Time:      t,
			Available: !bookedTimes[t.Unix()],
		})
	}
	return slots
}"}

